    public static async Task<string> RenderViewToStringAsync<TModel>(IRazorViewEngine viewEngine, ITempDataProvider tempDataProvider, IServiceProvider serviceProvider, IModelMetadataProvider metadataProvider, string viewName, TModel model)
    {
        var httpContext = new DefaultHttpContext { RequestServices = serviceProvider };
        var actionContext = new ActionContext(httpContext, new RouteData(), new ActionDescriptor());
        using var writer = new StringWriter();

        var viewResult = viewEngine.FindView(actionContext, viewName, false);
        if (viewResult.View == null)
            throw new ArgumentNullException($"{viewName} не найдено.");

        var viewContext = new ViewContext(
            actionContext,
            viewResult.View,
            new ViewDataDictionary<TModel>(metadataProvider, modelState: new ModelStateDictionary())
            {
                Model = model
            },
            tempData: new TempDataDictionary(httpContext, tempDataProvider),
            writer,
            new HtmlHelperOptions()
        );

        await viewResult.View.RenderAsync(viewContext);
        return writer.ToString();
    }

